import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface TopStory {
  headline: string;
  source: string;
  timeAgo: string;
}

interface NewsData {
  topStories: TopStory[];
}

export default function Widget() {
  const newsData = response.data as NewsData;
  const { topStories } = newsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            Top News Headlines
          </Typography>
          {topStories.map((story, index) => (
            <Box key={index}>
              <Typography variant="body1" fontWeight={500} sx={{ color: '#333' }}>
                {story.headline}
              </Typography>
              <Stack direction="row" spacing={1} sx={{ mt: 0.5 }}>
                <Chip label={story.source} sx={{ fontSize: '11px', bgcolor: '#E0F7FA', color: '#009688' }} />
                <Typography variant="caption" sx={{ color: '#666' }}>
                  {story.timeAgo}
                </Typography>
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
